#include <stdio.h>
int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        for(int i=0;i<N;i++){int x; scanf("%d", &x);} // discard array elements
        printf("Types of searching techniques: \n");
        printf("1. Linear Search\n");
        printf("2. Binary Search\n");
        printf("Types of sorting techniques: \n");
        printf("1. Bubble Sort\n");
        printf("2. Selection Sort\n");
        printf("3. Insertion Sort\n");
        printf("Linear Search: \n");
        printf("Linear search is a simple searching algorithm that works by iterating through each element in the array until it finds the target element.\n");
    }
    return 0;
}

